#include <stdio.h>
int main() {
    int arr[5] = {20, 30, 40, 50, 60};
    int *ptr;
    ptr = arr;
    printf("1번. %d\n", ++*ptr);
    printf("2번. %d\n", *(arr+1));
    printf("3번. %d\n", *ptr++);
    printf("4번. %d\n", ++*ptr);
    printf("5번. %d\n", *arr+1);
    printf("6번. %d\n", *ptr++);
    printf("7번. %d\n", *ptr+1);
}

