#include <stdio.h>
int main() {
    int x = 20;
    int y = 25;
    int z = x++ + --y;
    int w = ++x + y--;
    printf("%d\n", x);
    printf("%d\n", y);
    printf("%d\n", z);
    printf("%d\n", w);
    return 0;
}

#include <stdio.h>
int isP(int num) {
    if (num <= 1) return 0;
    for (int i = 2; i < num; i++) {
        if (num % i == 0) return 0;
    }
    return 1;
}
int main() {
    for (int i = 1; i <= 50; i++) {
        if (isP(i)) printf("%d ", i);
    }
    return 0;
}
